const sensitiveFields = ['password', 'token', 'ssn', 'creditCard', 'cvv'];

function sanitizeForLog(obj) {
  const sanitized = { ...obj };
  for (const field of sensitiveFields) {
    if (sanitized[field]) sanitized[field] = '[REDACTED]';
  }
  return sanitized;
}

logger.info('Payment processed', sanitizeForLog(paymentData));

// Encrypt PII before sending to external service
const crypto = require('crypto');

function encryptPII(data, key) {
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);
  const encrypted = Buffer.concat([cipher.update(JSON.stringify(data)), cipher.final()]);
  return { iv: iv.toString('hex'), data: encrypted.toString('hex'), tag: cipher.getAuthTag().toString('hex') };
}

